BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "Conductores" (
	"Id"	INTEGER NOT NULL,
	"Nombre"	TEXT NOT NULL,
	"Activo"	INTEGER NOT NULL,
	CONSTRAINT "PK_Conductores" PRIMARY KEY("Id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "Festivos" (
	"Id"	INTEGER NOT NULL,
	"Fecha"	TEXT NOT NULL,
	"Nombre"	TEXT,
	CONSTRAINT "PK_Festivos" PRIMARY KEY("Id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "GastosAdministrativos" (
	"Id"	INTEGER NOT NULL,
	"Fecha"	TEXT NOT NULL,
	"Concepto"	TEXT NOT NULL,
	"Valor"	TEXT NOT NULL,
	"Observaciones"	TEXT NOT NULL,
	"Placa"	TEXT NOT NULL DEFAULT '',
	CONSTRAINT "PK_GastosAdministrativos" PRIMARY KEY("Id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "LiquidacionesDiarias" (
	"Id"	INTEGER NOT NULL,
	"VehiculoId"	INTEGER NOT NULL,
	"ConductorId"	INTEGER,
	"Fecha"	TEXT NOT NULL,
	"Descripcion"	TEXT,
	"Producido"	TEXT NOT NULL,
	"Gastos"	TEXT,
	"Ahorro"	TEXT,
	"Saldo"	TEXT NOT NULL,
	"PicoYPlaca"	INTEGER NOT NULL,
	"EstadoDia"	TEXT NOT NULL DEFAULT '',
	CONSTRAINT "PK_LiquidacionesDiarias" PRIMARY KEY("Id" AUTOINCREMENT),
	CONSTRAINT "FK_LiquidacionesDiarias_Conductores_ConductorId" FOREIGN KEY("ConductorId") REFERENCES "Conductores"("Id"),
	CONSTRAINT "FK_LiquidacionesDiarias_Vehiculos_VehiculoId" FOREIGN KEY("VehiculoId") REFERENCES "Vehiculos"("Id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "Mantenimientos" (
	"Id"	INTEGER NOT NULL,
	"VehiculoId"	INTEGER NOT NULL,
	"Descripcion"	TEXT,
	"Valor"	decimal(18, 2) NOT NULL,
	"Fecha"	TEXT NOT NULL,
	"Kilometraje"	INTEGER,
	"ProximoCambio"	INTEGER,
	"Taller"	TEXT,
	"Garantia"	TEXT,
	"Iva"	TEXT,
	"TipoMantenimientoId"	INTEGER NOT NULL,
	CONSTRAINT "PK_Mantenimientos" PRIMARY KEY("Id" AUTOINCREMENT),
	CONSTRAINT "FK_Mantenimientos_TiposMantenimiento_TipoMantenimientoId" FOREIGN KEY("TipoMantenimientoId") REFERENCES "TiposMantenimiento"("Id") ON DELETE CASCADE,
	CONSTRAINT "FK_Mantenimientos_Vehiculos_VehiculoId" FOREIGN KEY("VehiculoId") REFERENCES "Vehiculos"("Id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "TiposMantenimiento" (
	"Id"	INTEGER NOT NULL,
	"Nombre"	TEXT NOT NULL,
	CONSTRAINT "PK_TiposMantenimiento" PRIMARY KEY("Id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "Usuarios" (
	"Id"	INTEGER NOT NULL,
	"NombreUsuario"	TEXT NOT NULL,
	"Clave"	TEXT NOT NULL,
	"NombreCompleto"	TEXT NOT NULL,
	CONSTRAINT "PK_Usuarios" PRIMARY KEY("Id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "Vehiculos" (
	"Id"	INTEGER NOT NULL,
	"Modelo"	TEXT,
	"Placa"	TEXT NOT NULL,
	"UsuarioId"	TEXT,
	CONSTRAINT "PK_Vehiculos" PRIMARY KEY("Id" AUTOINCREMENT)
);
CREATE INDEX IF NOT EXISTS "IX_LiquidacionesDiarias_ConductorId" ON "LiquidacionesDiarias" (
	"ConductorId"
);
CREATE INDEX IF NOT EXISTS "IX_LiquidacionesDiarias_VehiculoId" ON "LiquidacionesDiarias" (
	"VehiculoId"
);
CREATE INDEX IF NOT EXISTS "IX_Mantenimientos_TipoMantenimientoId" ON "Mantenimientos" (
	"TipoMantenimientoId"
);
CREATE INDEX IF NOT EXISTS "IX_Mantenimientos_VehiculoId" ON "Mantenimientos" (
	"VehiculoId"
);
COMMIT;
